package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique {
    private Integer id;
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique extends Oeuvre {
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
        super();
        setClasse("musique");
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package controllers;

import entities.Galerie;
import javafx.fxml.FXML;
import javafx.scene.control.Alert;
import javafx.scene.control.Label;
import javafx.scene.control.TextArea;
import javafx.scene.control.TextField;
import javafx.stage.Stage;

public class GalerieFormController {

    @FXML
    private Label formTitleLabel;

    @FXML
    private TextField nomField;

    @FXML
    private TextField adresseField;

    @FXML
    private TextField localisationField;

    @FXML
    private TextField capaciteField;

    @FXML
    private TextArea descriptionArea;

    private Stage dialogStage;
    private Galerie originalGalerie;
    private Galerie resultGalerie;

    public void setDialogStage(Stage dialogStage) {
        this.dialogStage = dialogStage;
    }

    public void setGalerie(Galerie galerie) {
        this.originalGalerie = galerie;
        if (galerie == null) {
            formTitleLabel.setText("Ajouter une galerie");
            return;
        }

        formTitleLabel.setText("Modifier la galerie");
        nomField.setText(galerie.getNom());
        adresseField.setText(galerie.getAdresse());
        localisationField.setText(galerie.getLocalisation());
        capaciteField.setText(galerie.getCapaciteMax() == null ? "" : String.valueOf(galerie.getCapaciteMax()));
        descriptionArea.setText(galerie.getDescription());
    }

    public Galerie getResultGalerie() {
        return resultGalerie;
    }

    @FXML
    private void onSaveClick() {
        String nom = nomField.getText() == null ? "" : nomField.getText().trim();
        String adresse = adresseField.getText() == null ? "" : adresseField.getText().trim();
        String localisation = localisationField.getText() == null ? "" : localisationField.getText().trim();
        String capaciteText = capaciteField.getText() == null ? "" : capaciteField.getText().trim();
        String description = descriptionArea.getText() == null ? "" : descriptionArea.getText().trim();

        if (nom.isEmpty() || adresse.isEmpty() || localisation.isEmpty() || capaciteText.isEmpty()) {
            showValidationAlert("Veuillez remplir les champs obligatoires.");
            return;
        }

        int capacite;
        try {
            capacite = Integer.parseInt(capaciteText);
            if (capacite <= 0) {
                showValidationAlert("La capacite doit etre superieure a 0.");
                return;
            }
        } catch (NumberFormatException e) {
            showValidationAlert("La capacite max doit etre un nombre entier.");
            return;
        }

        Galerie galerie = new Galerie();
        if (originalGalerie != null) {
            galerie.setId(originalGalerie.getId());
        }
        galerie.setNom(nom);
        galerie.setAdresse(adresse);
        galerie.setLocalisation(localisation);
        galerie.setDescription(description);
        galerie.setCapaciteMax(capacite);

        resultGalerie = galerie;
        closeDialog();
    }

    @FXML
    private void onCancelClick() {
        resultGalerie = null;
        closeDialog();
    }

    private void closeDialog() {
        if (dialogStage != null) {
            dialogStage.close();
        }
    }

    private void showValidationAlert(String message) {
        Alert alert = new Alert(Alert.AlertType.WARNING);
        alert.setTitle("Validation");
        alert.setHeaderText("Formulaire invalide");
        alert.setContentText(message);
        alert.showAndWait();
    }
}

package controllers;

import entities.Galerie;
import javafx.fxml.FXML;
import javafx.scene.control.Label;
import javafx.scene.control.TextArea;
import javafx.scene.control.TextField;
import javafx.stage.Stage;

public class GalerieFormController {

    @FXML
    private Label formTitleLabel;

    @FXML
    private TextField nomField;

    @FXML
    private TextField adresseField;

    @FXML
    private TextField localisationField;

    @FXML
    private TextField capaciteField;

    @FXML
    private TextArea descriptionArea;

    @FXML
    private Label validationErrorLabel;

    private Stage dialogStage;
    private Galerie originalGalerie;
    private Galerie resultGalerie;

    @FXML
    public void initialize() {
        clearValidationError();
        nomField.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        adresseField.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        localisationField.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        capaciteField.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
        descriptionArea.textProperty().addListener((obs, oldValue, newValue) -> clearValidationError());
    }

    public void setDialogStage(Stage dialogStage) {
        this.dialogStage = dialogStage;
    }

    public void setGalerie(Galerie galerie) {
        this.originalGalerie = galerie;
        clearValidationError();
        if (galerie == null) {
            formTitleLabel.setText("Ajouter une galerie");
            nomField.clear();
            adresseField.clear();
            localisationField.clear();
            capaciteField.clear();
            descriptionArea.clear();
            return;
        }

        formTitleLabel.setText("Modifier la galerie");
        nomField.setText(galerie.getNom());
        adresseField.setText(galerie.getAdresse());
        localisationField.setText(galerie.getLocalisation());
        capaciteField.setText(galerie.getCapaciteMax() == null ? "" : String.valueOf(galerie.getCapaciteMax()));
        descriptionArea.setText(galerie.getDescription());
    }

    public Galerie getResultGalerie() {
        return resultGalerie;
    }

    @FXML
    private void onSaveClick() {
        clearValidationError();
        String nom = nomField.getText() == null ? "" : nomField.getText().trim();
        String adresse = adresseField.getText() == null ? "" : adresseField.getText().trim();
        String localisation = localisationField.getText() == null ? "" : localisationField.getText().trim();
        String capaciteText = capaciteField.getText() == null ? "" : capaciteField.getText().trim();
        String description = descriptionArea.getText() == null ? "" : descriptionArea.getText().trim();

        if (nom.isEmpty() || adresse.isEmpty() || localisation.isEmpty() || capaciteText.isEmpty()) {
            showValidationError("Veuillez remplir les champs obligatoires.");
            return;
        }

        int capacite;
        try {
            capacite = Integer.parseInt(capaciteText);
            if (capacite <= 0) {
                showValidationError("La capacite doit etre superieure a 0.");
                return;
            }
        } catch (NumberFormatException e) {
            showValidationError("La capacite max doit etre un nombre entier.");
            return;
        }

        Galerie galerie = new Galerie();
        if (originalGalerie != null) {
            galerie.setId(originalGalerie.getId());
        }
        galerie.setNom(nom);
        galerie.setAdresse(adresse);
        galerie.setLocalisation(localisation);
        galerie.setDescription(description);
        galerie.setCapaciteMax(capacite);

        resultGalerie = galerie;
        closeDialog();
    }

    @FXML
    private void onCancelClick() {
        resultGalerie = null;
        closeDialog();
    }

    private void closeDialog() {
        if (dialogStage != null) {
            dialogStage.close();
        }
    }

    private void showValidationError(String message) {
        validationErrorLabel.setText(message);
        validationErrorLabel.setVisible(true);
        validationErrorLabel.setManaged(true);
    }

    private void clearValidationError() {
        if (validationErrorLabel == null) {
            return;
        }
        validationErrorLabel.setText("");
        validationErrorLabel.setVisible(false);
        validationErrorLabel.setManaged(false);
    }
}

package controllers.amateur;

import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.layout.HBox;

import java.util.function.Consumer;

public class MiniAudioPlayerController {

    @FXML
    private HBox playerBar;

    @FXML
    private Button togglePlayButton;

    private Consumer<String> navigationHandler;
    private boolean playing;

    @FXML
    public void initialize() {
        playerBar.setVisible(false);
        playerBar.setManaged(false);
    }

    public void setNavigationHandler(Consumer<String> navigationHandler) {
        this.navigationHandler = navigationHandler;
    }

    public void setVisibleForRoute(String route) {
        boolean isMusicPage = "musique".equals(route);
        playerBar.setVisible(!isMusicPage);
        playerBar.setManaged(!isMusicPage);
    }

    @FXML
    private void onTogglePlay() {
        playing = !playing;
        togglePlayButton.setText(playing ? "||" : ">");
    }

    @FXML
    private void onPrevTrack() {
        // Placeholder for queue previous action.
    }

    @FXML
    private void onNextTrack() {
        // Placeholder for queue next action.
    }

    @FXML
    private void onOpenMusic() {
        if (navigationHandler != null) {
            navigationHandler.accept("musique");
        }
    }
}

package entities;

import java.time.LocalDate;
import java.time.LocalDateTime;

public class Personne {
    private Integer id;
    private String photoProfil;
    private String resetToken;
    private LocalDateTime resetTokenExpires;
    private String nom;
    private String prenom;
    private LocalDate dateNaissance;
    private String email;
    private String mdp;
    private String role;
    private String statut;
    private LocalDate dateInscription;
    private String numTel;
    private String ville;
    private String biographie;
    private String specialite;
    private String centreInteret;
    private String photoReferencePath;

    // Legacy field kept for compatibility with existing ServicePersonne.
    private Integer age;

    public Personne() {
    }

    public Personne(String nom, String prenom, Integer age) {
        this.nom = nom;
        this.prenom = prenom;
        this.age = age;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getPhotoProfil() {
        return photoProfil;
    }

    public void setPhotoProfil(String photoProfil) {
        this.photoProfil = photoProfil;
    }

    public String getResetToken() {
        return resetToken;
    }

    public void setResetToken(String resetToken) {
        this.resetToken = resetToken;
    }

    public LocalDateTime getResetTokenExpires() {
        return resetTokenExpires;
    }

    public void setResetTokenExpires(LocalDateTime resetTokenExpires) {
        this.resetTokenExpires = resetTokenExpires;
    }

    public String getNom() {
        return nom;
    }

    public void setNom(String nom) {
        this.nom = nom;
    }

    public String getPrenom() {
        return prenom;
    }

    public void setPrenom(String prenom) {
        this.prenom = prenom;
    }

    public LocalDate getDateNaissance() {
        return dateNaissance;
    }

    public void setDateNaissance(LocalDate dateNaissance) {
        this.dateNaissance = dateNaissance;
    }

    public String getEmail() {
        return email;
    }

    public void setEmail(String email) {
        this.email = email;
    }

    public String getMdp() {
        return mdp;
    }

    public void setMdp(String mdp) {
        this.mdp = mdp;
    }

    public String getRole() {
        return role;
    }

    public void setRole(String role) {
        this.role = role;
    }

    public String getStatut() {
        return statut;
    }

    public void setStatut(String statut) {
        this.statut = statut;
    }

    public LocalDate getDateInscription() {
        return dateInscription;
    }

    public void setDateInscription(LocalDate dateInscription) {
        this.dateInscription = dateInscription;
    }

    public String getNumTel() {
        return numTel;
    }

    public void setNumTel(String numTel) {
        this.numTel = numTel;
    }

    public String getVille() {
        return ville;
    }

    public void setVille(String ville) {
        this.ville = ville;
    }

    public String getBiographie() {
        return biographie;
    }

    public void setBiographie(String biographie) {
        this.biographie = biographie;
    }

    public String getSpecialite() {
        return specialite;
    }

    public void setSpecialite(String specialite) {
        this.specialite = specialite;
    }

    public String getCentreInteret() {
        return centreInteret;
    }

    public void setCentreInteret(String centreInteret) {
        this.centreInteret = centreInteret;
    }

    public String getPhotoReferencePath() {
        return photoReferencePath;
    }

    public void setPhotoReferencePath(String photoReferencePath) {
        this.photoReferencePath = photoReferencePath;
    }

    public Integer getAge() {
        return age;
    }

    public void setAge(Integer age) {
        this.age = age;
    }

    @Override
    public String toString() {
        return "Personne{" +
                "id=" + id +
                ", nom='" + nom + '\'' +
                ", prenom='" + prenom + '\'' +
                ", email='" + email + '\'' +
                ", role='" + role + '\'' +
                ", statut='" + statut + '\'' +
                '}';
    }
}

