.app-root.dark-mode .section-title,
.app-root.dark-mode .stat-number {
    -fx-text-fill: #edf2ff;
}

.app-root.dark-mode .page-subtitle,
.app-root.dark-mode .stat-label,
.app-root.dark-mode .section-subtitle,
.app-root.dark-mode .calendar-day,
.app-root.dark-mode .calendar-day-header {
    -fx-text-fill: #b7c4dc;
}

.app-root {
    -fx-font-family: "Segoe UI", Arial, sans-serif;
    -fx-background-color: #d2d7df;
}

.sidebar {
    -fx-background-color: #3d3bc2;
    -fx-min-width: 260;
    -fx-pref-width: 260;
    -fx-max-width: 260;
}

.sidebar-brand {
    -fx-padding: 8 10 18 10;
}

.brand-dot {
    -fx-text-fill: #eef0ff;
    -fx-font-size: 24px;
    -fx-font-weight: bold;
}

.brand-label {
    -fx-text-fill: white;
    -fx-font-size: 28px;
    -fx-font-weight: 700;
}

.nav-item,
.nav-sub-item {
    -fx-background-color: transparent;
    -fx-text-fill: #f0f2ff;
    -fx-font-size: 14px;
    -fx-font-weight: 700;
    -fx-alignment: CENTER_LEFT;
    -fx-padding: 9 14 9 14;
    -fx-background-radius: 8;
    -fx-border-radius: 8;
    -fx-cursor: hand;
}

.nav-sub-item {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
    -fx-padding: 8 14 8 26;
}

.sub-menu {
    -fx-padding: 0 0 2 0;
}

.nav-item:hover,
.nav-sub-item:hover {
    -fx-background-color: rgba(255, 255, 255, 0.12);
}

.nav-item.active,
.nav-sub-item.active {
    -fx-background-color: rgba(255, 255, 255, 0.2);
    -fx-text-fill: #ffffff;
}

.sidebar.collapsed .brand-label,
.sidebar.collapsed .sub-menu {
    -fx-opacity: 0;
}

.navbar {
    -fx-background-color: #f8f9fb;
    -fx-border-color: #d9dce3;
    -fx-border-width: 0 0 1 0;
}

.search-field {
    -fx-background-color: #f4f5f7;
    -fx-border-color: #c8cdd7;
    -fx-border-radius: 6;
    -fx-background-radius: 6;
    -fx-padding: 0 10 0 10;
}

.icon-button {
    -fx-background-color: #eef1f5;
    -fx-border-color: #d4d9e1;
    -fx-background-radius: 17;
    -fx-border-radius: 17;
    -fx-text-fill: #3b4250;
    -fx-font-weight: 700;
    -fx-cursor: hand;
}

.menu-icon-button {
    -fx-background-color: #eef1f5;
    -fx-border-color: #d4d9e1;
    -fx-background-radius: 16;
    -fx-border-radius: 16;
}

.avatar-menu {
    -fx-background-color: #ebeff5;
    -fx-border-color: #cfd5e0;
    -fx-background-radius: 16;
    -fx-border-radius: 16;
    -fx-text-fill: #243146;
    -fx-font-weight: 700;
}

.content-area {
    -fx-background-color: #d2d7df;
}

.page-root {
    -fx-background-color: #d2d7df;
}

.page-title {
    -fx-font-size: 25px;
    -fx-font-weight: 700;
    -fx-text-fill: #1c2b3f;
}

.page-subtitle {
    -fx-font-size: 15px;
    -fx-text-fill: #314865;
}

.dashboard-scroll {
    -fx-background: #d2d7df;
    -fx-background-color: transparent;
}

.dashboard-scroll > .viewport {
    -fx-background-color: transparent;
}

.dashboard-card {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #edf0f4;
    -fx-border-radius: 12;
    -fx-effect: dropshadow(gaussian, rgba(60,60,60,0.08), 10, 0, 0, 2);
    -fx-min-width: 175;
    -fx-pref-width: 190;
    -fx-alignment: CENTER;
}

.dashboard-card:hover {
    -fx-effect: dropshadow(gaussian, rgba(60,60,60,0.15), 16, 0, 0, 4);
}

.icon-circle {
    -fx-background-radius: 20;
    -fx-min-width: 38;
    -fx-min-height: 38;
    -fx-max-width: 38;
    -fx-max-height: 38;
    -fx-alignment: CENTER;
}

.card-icon-text {
    -fx-font-weight: 700;
}

.icon-users {
    -fx-background-color: #e3f2fd;
    -fx-text-fill: #2196f3;
}

.icon-artistes {
    -fx-background-color: #f3e5f5;
    -fx-text-fill: #8e24aa;
}

.icon-amateurs {
    -fx-background-color: #fff3e0;
    -fx-text-fill: #ff9800;
}

.icon-oeuvres {
    -fx-background-color: #e0f7fa;
    -fx-text-fill: #43cea2;
}

.icon-reclam {
    -fx-background-color: #ffebee;
    -fx-text-fill: #e53935;
}

.icon-events {
    -fx-background-color: #e8eaf6;
    -fx-text-fill: #3949ab;
}

.stat-number {
    -fx-font-size: 30px;
    -fx-font-weight: 800;
    -fx-text-fill: #212529;
}

.stat-label {
    -fx-font-size: 14px;
    -fx-text-fill: #6c757d;
}

.list-card {
    -fx-background-color: white;
    -fx-background-radius: 12;
    -fx-border-color: #e8ecf2;
    -fx-border-radius: 12;
    -fx-effect: dropshadow(gaussian, rgba(60,60,60,0.07), 10, 0, 0, 2);
}

.section-title {
    -fx-font-size: 15px;
    -fx-font-weight: 700;
    -fx-text-fill: #2f3e52;
}

.section-subtitle {
    -fx-font-size: 12px;
    -fx-text-fill: #63758d;
}

.primary-action-button {
    -fx-background-color: #3d3bc2;
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 8;
    -fx-padding: 8 16 8 16;
    -fx-cursor: hand;
}

.primary-action-button:hover {
    -fx-background-color: #3432ad;
}

.secondary-action-button {
    -fx-background-color: #f1f4f8;
    -fx-border-color: #ced6e0;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-text-fill: #2f3e52;
    -fx-font-weight: 600;
    -fx-cursor: hand;
}

.danger-action-button {
    -fx-background-color: #ffe8ea;
    -fx-border-color: #f3b7be;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-text-fill: #a63038;
    -fx-font-weight: 700;
    -fx-cursor: hand;
}

.gallery-search-field {
    -fx-background-color: #f6f7fb;
    -fx-border-color: #d7dce6;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 8 10 8 10;
}

.gallery-form-text-area {
    -fx-background-color: #f6f7fb;
    -fx-border-color: #d7dce6;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 8 10 8 10;
    -fx-background-insets: 0;
}

.gallery-form-text-area .content {
    -fx-background-color: #f6f7fb;
    -fx-background-radius: 8;
}

.form-validation-error {
    -fx-text-fill: #c62828;
    -fx-font-size: 12px;
    -fx-font-weight: 600;
}

.gallery-scroll,
.gallery-scroll > .viewport {
    -fx-background-color: transparent;
}

.gallery-flow {
    -fx-background-color: transparent;
}

.gallery-card {
    -fx-background-color: #fdfefe;
    -fx-border-color: #e4e9f0;
    -fx-border-radius: 12;
    -fx-background-radius: 12;
    -fx-effect: dropshadow(gaussian, rgba(60,60,60,0.08), 8, 0, 0, 1);
}

.gallery-card:hover {
    -fx-effect: dropshadow(gaussian, rgba(60,60,60,0.15), 12, 0, 0, 3);
}

.gallery-name {
    -fx-font-size: 17px;
    -fx-font-weight: 700;
    -fx-text-fill: #223247;
}

.gallery-capacity {
    -fx-font-size: 12px;
    -fx-text-fill: #5d7090;
}

.gallery-meta {
    -fx-font-size: 13px;
    -fx-text-fill: #3c4f67;
}

.gallery-details {
    -fx-background-color: #f5f7fb;
    -fx-background-radius: 8;
    -fx-border-color: #dde4ef;
    -fx-border-radius: 8;
}

.gallery-detail-label {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: #41566f;
}

.gallery-detail-value {
    -fx-font-size: 12px;
    -fx-text-fill: #42586f;
}

.gallery-form-root {
    -fx-background-color: #f5f7fb;
    -fx-min-width: 520;
}

.calendar-day-header {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: #5a6c82;
}

.calendar-day {
    -fx-min-width: 28;
    -fx-pref-width: 28;
    -fx-alignment: CENTER;
    -fx-text-fill: #41566f;
    -fx-padding: 4;
}

.calendar-day.today {
    -fx-background-color: #fff3e0;
    -fx-background-radius: 14;
    -fx-text-fill: #ff9800;
    -fx-font-weight: 700;
}

.app-root.dark-mode {
    -fx-background-color: #1a2235;
}

.app-root.dark-mode .content-area,
.app-root.dark-mode .page-root {
    -fx-background-color: #1f2a40;
}

.app-root.dark-mode .list-card,
.app-root.dark-mode .dashboard-card,
.app-root.dark-mode .navbar {
    -fx-background-color: #243149;
    -fx-border-color: #324262;
}

.app-root.dark-mode .page-title,
.app-root.dark-mode .section-title,
.app-root.dark-mode .stat-number {
    -fx-text-fill: #edf2ff;
}

.app-root.dark-mode .page-subtitle,
.app-root.dark-mode .stat-label,
.app-root.dark-mode .section-subtitle,
.app-root.dark-mode .calendar-day,
.app-root.dark-mode .calendar-day-header {
    -fx-text-fill: #b7c4dc;
}
